import { rand, useIntervalFn } from '@vueuse/core'
import { shallowRef } from 'vue'

const greetings = ['Hello', 'Hi', 'Yo!', 'Hey', 'Hola', 'こんにちは', 'Bonjour', 'Salut!', 'Hello', 'Привет']
